def llm_judge(input_text: str, model_output: str, criteria: str) -> dict:
    """Use a model as a judge to score another model's output."""
    judge_prompt = f"""You are evaluating a model's response.

Criteria: {criteria}

Input to the model: {input_text}

Model response: {model_output}

Rate the response on a scale of 1-5, where:
1 = Does not meet the criteria at all
3 = Partially meets the criteria
5 = Fully meets the criteria

Respond with a JSON object: {{"score": <1-5>, "reason": "<one sentence>"}}"""

    import anthropic, json
    client = anthropic.Anthropic()
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=100,
        messages=[{"role": "user", "content": judge_prompt}]
    )
    return json.loads(response.content[0].text)

# Example
result = llm_judge(
    input_text="What is backpropagation?",
    model_output="Backpropagation computes gradients by...",
    criteria="Technically accurate, understandable to a developer, under 100 words"
)
# → {"score": 4, "reason": "Accurate and concise, but missing a concrete example"}
